import{_ as a,c as s,o as i,ag as n}from"./chunks/framework.DK1-H3E1.js";const g=JSON.parse('{"title":"Syncthing - 开源 P2P 文件同步工具","description":"","frontmatter":{"order":1},"headers":[],"relativePath":"github-projects/syncthing.md","filePath":"github-projects/syncthing.md","lastUpdated":1775480712000}'),l={name:"github-projects/syncthing.md"};function e(r,t,d,h,p,o){return i(),s("div",null,t[0]||(t[0]=[n(`<h1 id="syncthing-开源-p2p-文件同步工具" tabindex="-1">Syncthing - 开源 P2P 文件同步工具 <a class="header-anchor" href="#syncthing-开源-p2p-文件同步工具" aria-label="Permalink to &quot;Syncthing - 开源 P2P 文件同步工具&quot;">​</a></h1><h2 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h2><p><strong>Syncthing</strong> 是一个开源的持续文件同步程序，可以在两台或多台计算机之间实时同步文件。</p><table tabindex="0"><thead><tr><th>属性</th><th>信息</th></tr></thead><tbody><tr><td>GitHub</td><td><a href="https://github.com/syncthing/syncthing" target="_blank" rel="noreferrer">syncthing/syncthing</a></td></tr><tr><td>Stars</td><td>81,455+ ⭐</td></tr><tr><td>最新版本</td><td>v2.0.15</td></tr><tr><td>许可证</td><td>MPL-2.0</td></tr><tr><td>支持平台</td><td>Windows, macOS, Linux, Android, iOS</td></tr></tbody></table><h2 id="核心特点" tabindex="-1">核心特点 <a class="header-anchor" href="#核心特点" aria-label="Permalink to &quot;核心特点&quot;">​</a></h2><h3 id="🔒-隐私优先" tabindex="-1">🔒 隐私优先 <a class="header-anchor" href="#🔒-隐私优先" aria-label="Permalink to &quot;🔒 隐私优先&quot;">​</a></h3><ul><li><strong>数据不经过云端</strong> — 文件直接在设备间传输，无需第三方服务器</li><li><strong>端到端加密</strong> — 所有传输都经过 TLS 加密</li><li><strong>开源透明</strong> — 代码完全公开，可审计安全性</li></ul><h3 id="🌐-跨平台支持" tabindex="-1">🌐 跨平台支持 <a class="header-anchor" href="#🌐-跨平台支持" aria-label="Permalink to &quot;🌐 跨平台支持&quot;">​</a></h3><table tabindex="0"><thead><tr><th>平台</th><th>支持情况</th></tr></thead><tbody><tr><td>Windows</td><td>✅ 官方支持</td></tr><tr><td>macOS</td><td>✅ 官方支持</td></tr><tr><td>Linux</td><td>✅ 官方支持</td></tr><tr><td>Android</td><td>✅ 官方 App</td></tr><tr><td>iOS</td><td>✅ App Store 可下载</td></tr></tbody></table><h3 id="💰-完全免费" tabindex="-1">💰 完全免费 <a class="header-anchor" href="#💰-完全免费" aria-label="Permalink to &quot;💰 完全免费&quot;">​</a></h3><ul><li>无需付费订阅</li><li>无文件大小限制</li><li>无设备数量限制</li><li>无需注册账号</li></ul><h2 id="与其他方案对比" tabindex="-1">与其他方案对比 <a class="header-anchor" href="#与其他方案对比" aria-label="Permalink to &quot;与其他方案对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>Syncthing</th><th>云存储 (Dropbox等)</th><th>Obsidian Git</th></tr></thead><tbody><tr><td>价格</td><td>免费</td><td>付费/有限免费</td><td>免费</td></tr><tr><td>隐私性</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐</td><td>⭐⭐⭐⭐</td></tr><tr><td>需要云服务</td><td>❌</td><td>✅</td><td>✅ (GitHub)</td></tr><tr><td>设备需同时在线</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>版本控制</td><td>基础</td><td>基础</td><td>完整 Git</td></tr><tr><td>配置复杂度</td><td>中等</td><td>简单</td><td>中等</td></tr><tr><td>手机稳定性</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐</td></tr></tbody></table><h2 id="典型使用场景" tabindex="-1">典型使用场景 <a class="header-anchor" href="#典型使用场景" aria-label="Permalink to &quot;典型使用场景&quot;">​</a></h2><h3 id="_1-obsidian-笔记同步" tabindex="-1">1. Obsidian 笔记同步 <a class="header-anchor" href="#_1-obsidian-笔记同步" aria-label="Permalink to &quot;1. Obsidian 笔记同步&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>电脑端                              手机端</span></span>
<span class="line"><span>+------------------+              +------------------+</span></span>
<span class="line"><span>| Syncthing        |              | Syncthing App    |</span></span>
<span class="line"><span>| Obsidian 库      | &lt;---------&gt; | Obsidian 库      |</span></span>
<span class="line"><span>| 自动同步变更      |   P2P 直连   | 自动同步变更      |</span></span>
<span class="line"><span>+------------------+              +------------------+</span></span></code></pre></div><p><strong>优势</strong>：</p><ul><li>无需付费订阅 Obsidian Sync</li><li>笔记数据完全私密</li><li>同步速度快</li></ul><h3 id="_2-文档同步" tabindex="-1">2. 文档同步 <a class="header-anchor" href="#_2-文档同步" aria-label="Permalink to &quot;2. 文档同步&quot;">​</a></h3><ul><li>工作文档在多台电脑间同步</li><li>照片从手机自动备份到电脑</li><li>代码项目在多设备间同步</li></ul><h3 id="_3-家庭数据共享" tabindex="-1">3. 家庭数据共享 <a class="header-anchor" href="#_3-家庭数据共享" aria-label="Permalink to &quot;3. 家庭数据共享&quot;">​</a></h3><ul><li>家庭照片库共享</li><li>音乐/视频库同步</li><li>无需上传到云端</li></ul><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><h3 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h3><p><strong>Windows</strong>:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">winget install Syncthing.Syncthing</span></span></code></pre></div><p><strong>macOS</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> syncthing</span></span></code></pre></div><p><strong>Linux</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> syncthing</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Debian/Ubuntu</span></span></code></pre></div><p><strong>Android</strong>: <a href="https://play.google.com/store/apps/details?id=com.nutomic.syncthingandroid" target="_blank" rel="noreferrer">Google Play</a> 或 <a href="https://f-droid.org/packages/com.nutomic.syncthingandroid/" target="_blank" rel="noreferrer">F-Droid</a></p><p><strong>iOS</strong>: <a href="https://apps.apple.com/app/syncthing/id1583961890" target="_blank" rel="noreferrer">App Store</a></p><h3 id="基本配置流程" tabindex="-1">基本配置流程 <a class="header-anchor" href="#基本配置流程" aria-label="Permalink to &quot;基本配置流程&quot;">​</a></h3><ol><li><p><strong>电脑端启动 Syncthing</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">syncthing</span></span></code></pre></div><p>自动打开 Web GUI: <a href="http://localhost:8384" target="_blank" rel="noreferrer">http://localhost:8384</a></p></li><li><p><strong>获取设备 ID</strong></p><ul><li>点击右上角「操作」→「显示 ID」</li><li>记录设备 ID 或生成二维码</li></ul></li><li><p><strong>手机端添加设备</strong></p><ul><li>打开 Syncthing App</li><li>扫描电脑端二维码或输入设备 ID</li><li>在电脑端确认连接请求</li></ul></li><li><p><strong>配置同步文件夹</strong></p><ul><li>电脑端：添加文件夹，选择 Obsidian 库路径</li><li>手机端：添加同名文件夹，选择存储位置</li><li><strong>关键</strong>：文件夹 ID 必须两端一致</li></ul></li><li><p><strong>开始同步</strong></p><ul><li>两端确认共享</li><li>文件自动同步</li></ul></li></ol><h2 id="高级配置" tabindex="-1">高级配置 <a class="header-anchor" href="#高级配置" aria-label="Permalink to &quot;高级配置&quot;">​</a></h2><h3 id="跨网络同步" tabindex="-1">跨网络同步 <a class="header-anchor" href="#跨网络同步" aria-label="Permalink to &quot;跨网络同步&quot;">​</a></h3><p>如果设备不在同一局域网，有三种方案：</p><p><strong>方案 A：中继服务器（默认启用）</strong></p><ul><li>自动使用 Syncthing 官方中继</li><li>无需配置，但速度较慢</li></ul><p><strong>方案 B：端口转发</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 路由器配置</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">外部端口</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 22000</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> →</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 内部</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> IP:22000</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 防火墙开放</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ufw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> allow</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 22000/tcp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Linux</span></span></code></pre></div><p><strong>方案 C：Tailscale 组网（推荐）</strong></p><ol><li>在所有设备安装 <a href="https://tailscale.com" target="_blank" rel="noreferrer">Tailscale</a></li><li>登录同一账号</li><li>设备自动组成虚拟局域网</li><li>Syncthing 自动发现</li></ol><h3 id="忽略模式" tabindex="-1">忽略模式 <a class="header-anchor" href="#忽略模式" aria-label="Permalink to &quot;忽略模式&quot;">​</a></h3><p>创建 <code>.stignore</code> 文件排除不需要同步的内容：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Obsidian 工作区（设备特定）</span></span>
<span class="line"><span>.obsidian/workspace.json</span></span>
<span class="line"><span>.obsidian/workspace-mobile.json</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 临时文件</span></span>
<span class="line"><span>.trash/</span></span>
<span class="line"><span>*.tmp</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 系统文件</span></span>
<span class="line"><span>.DS_Store</span></span>
<span class="line"><span>Thumbs.db</span></span></code></pre></div><h3 id="版本控制" tabindex="-1">版本控制 <a class="header-anchor" href="#版本控制" aria-label="Permalink to &quot;版本控制&quot;">​</a></h3><p>在文件夹设置中启用版本控制：</p><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>垃圾箱</td><td>删除文件移到 .stversions</td></tr><tr><td>简单版本控制</td><td>保留最近 N 个版本</td></tr><tr><td>阶段性版本控制</td><td>按时间保留版本</td></tr></tbody></table><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>解决方法</th></tr></thead><tbody><tr><td>设备无法发现</td><td>检查防火墙，确认 21027/UDP 开放</td></tr><tr><td>同步速度慢</td><td>使用端口转发或 Tailscale 替代中继</td></tr><tr><td>文件冲突</td><td>Syncthing 自动重命名冲突文件</td></tr><tr><td>手机后台不同步</td><td>关闭电池优化，允许后台运行</td></tr><tr><td>iOS 权限问题</td><td>在「文件」App 中授权 Syncthing</td></tr></tbody></table><h2 id="相关资源" tabindex="-1">相关资源 <a class="header-anchor" href="#相关资源" aria-label="Permalink to &quot;相关资源&quot;">​</a></h2><ul><li><strong>官网</strong>: <a href="https://syncthing.net" target="_blank" rel="noreferrer">syncthing.net</a></li><li><strong>GitHub</strong>: <a href="https://github.com/syncthing/syncthing" target="_blank" rel="noreferrer">syncthing/syncthing</a></li><li><strong>文档</strong>: <a href="https://docs.syncthing.net" target="_blank" rel="noreferrer">docs.syncthing.net</a></li><li><strong>论坛</strong>: <a href="https://forum.syncthing.net" target="_blank" rel="noreferrer">forum.syncthing.net</a></li></ul><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>Syncthing 是追求隐私和数据主权用户的最佳选择。虽然配置相对复杂，但一旦设置完成，就能享受免费、私密、无限制的文件同步体验。</p><p><strong>推荐人群</strong>：</p><ul><li>注重隐私的用户</li><li>不想付费订阅云服务</li><li>有多设备同步需求</li><li>开发者、技术爱好者</li></ul><p><strong>不太推荐</strong>：</p><ul><li>追求极致简单的用户</li><li>需要随时访问历史版本</li><li>设备经常离线</li></ul>`,60)]))}const b=a(l,[["render",e]]);export{g as __pageData,b as default};
